import{_ as t,o as e,c as l,a2 as r}from"./chunks/framework.Bjylvv1V.js";const p=JSON.parse('{"title":"연말 결산","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/year-end.md","filePath":"guide/scenarios/year-end.md","lastUpdated":1771991831000}'),i={name:"guide/scenarios/year-end.md"};function o(n,a,h,s,d,c){return e(),l("div",null,[...a[0]||(a[0]=[r(`<h1 id="연말-결산" tabindex="-1">연말 결산 <a class="header-anchor" href="#연말-결산" aria-label="Permalink to &quot;연말 결산&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 2시간 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 연 1회 (회계연도 말)</p></blockquote><p>회계연도의 모든 수입·지출을 확정하고, 최종 재무제표를 작성한 뒤, 차기 연도로 잔액을 이월하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 12월 월말 마감         (40분)  → 마지막 월의 일반 마감</span></span>
<span class="line"><span>2. 연간 재무제표 작성     (20분)  → 연간 시산표·대차대조표·손익계산서</span></span>
<span class="line"><span>3. 예산 대비 실적 확인    (15분)  → 세입세출서·예산결산서</span></span>
<span class="line"><span>4. 감사 준비 자료 출력    (15분)  → 각종 장부·보고서 인쇄</span></span>
<span class="line"><span>5. 년도이월 실행          (5분)   → 차기 연도로 잔액 이월</span></span>
<span class="line"><span>6. 차기 예산 등록         (15분)  → 새 연도 예산 입력</span></span>
<span class="line"><span>7. 연말정산 (급여)        (별도)  → 직원 소득세 정산</span></span></code></pre></div><hr><h2 id="_1단계-12월-월말-마감-40분" tabindex="-1">1단계: 12월 월말 마감 (40분) <a class="header-anchor" href="#_1단계-12월-월말-마감-40분" aria-label="Permalink to &quot;1단계: 12월 월말 마감 (40분)&quot;">​</a></h2><p>12월의 일반 월말 마감을 먼저 완료합니다.</p><p>상세 절차는 <a href="/guide/scenarios/month-closing.html">월말 마감</a> 시나리오를 참고하세요.</p><h3 id="연말-추가-확인-사항" tabindex="-1">연말 추가 확인 사항 <a class="header-anchor" href="#연말-추가-확인-사항" aria-label="Permalink to &quot;연말 추가 확인 사항&quot;">​</a></h3><ul><li>[ ] 12월분 모든 수납이 처리되었는가?</li><li>[ ] 12월분 모든 전표가 입력되었는가?</li><li>[ ] 모든 통장 잔액이 시스템과 일치하는가?</li><li>[ ] 미수금 잔액이 정확한가?</li><li>[ ] 장기수선충당금 잔액이 정확한가?</li><li>[ ] 12월 월마감이 완료되었는가?</li></ul><hr><h2 id="_2단계-연간-재무제표-작성-20분" tabindex="-1">2단계: 연간 재무제표 작성 (20분) <a class="header-anchor" href="#_2단계-연간-재무제표-작성-20분" aria-label="Permalink to &quot;2단계: 연간 재무제표 작성 (20분)&quot;">​</a></h2><h3 id="합계잔액시산표" tabindex="-1">합계잔액시산표 <a class="header-anchor" href="#합계잔액시산표" aria-label="Permalink to &quot;합계잔액시산표&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 합계잔액시산표 (ACCT4010)</p></blockquote><ol><li>기간 설정: 회계연도 전체 (예: 2026-01-01 ~ 2026-12-31)</li><li><strong>조회</strong> 실행</li><li>확인: <strong>차변 합계 = 대변 합계</strong></li></ol><h3 id="대차대조표" tabindex="-1">대차대조표 <a class="header-anchor" href="#대차대조표" aria-label="Permalink to &quot;대차대조표&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 대차대조표 (ACCT4020)</p></blockquote><p>회계연도 말 시점의 자산·부채·자본 현황입니다.</p><ul><li>[ ] 자산 총계 = 부채 총계 + 자본 총계인가?</li><li>[ ] 주요 자산 항목(보통예금, 미수금 등)이 실제와 일치하는가?</li></ul><h3 id="손익계산서" tabindex="-1">손익계산서 <a class="header-anchor" href="#손익계산서" aria-label="Permalink to &quot;손익계산서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 손익계산서 (ACCT4030)</p></blockquote><p>연간 수입·지출·당기순이익을 확인합니다.</p><h3 id="월별-손익계산서" tabindex="-1">월별 손익계산서 <a class="header-anchor" href="#월별-손익계산서" aria-label="Permalink to &quot;월별 손익계산서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 월별손익계산서 (ACCT4031)</p></blockquote><p>1~12월 월별 손익 추이를 확인합니다.</p><hr><h2 id="_3단계-예산-대비-실적-확인-15분" tabindex="-1">3단계: 예산 대비 실적 확인 (15분) <a class="header-anchor" href="#_3단계-예산-대비-실적-확인-15분" aria-label="Permalink to &quot;3단계: 예산 대비 실적 확인 (15분)&quot;">​</a></h2><h3 id="세입세출서" tabindex="-1">세입세출서 <a class="header-anchor" href="#세입세출서" aria-label="Permalink to &quot;세입세출서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 세입세출서 (ACCT4080)</p></blockquote><p>예산 대비 실적 달성률을 확인합니다.</p><ul><li>계산식: (실적 ÷ 예산) × 100</li><li>세입(수입), 세출(지출), 차인(차이)별로 확인 가능</li></ul><h3 id="예산결산서" tabindex="-1">예산결산서 <a class="header-anchor" href="#예산결산서" aria-label="Permalink to &quot;예산결산서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산결산서</p></blockquote><p>전기 기초잔액 + 당기 증감을 기준으로 예산 집행 결과를 확인합니다.</p><h3 id="예산실적대조표" tabindex="-1">예산실적대조표 <a class="header-anchor" href="#예산실적대조표" aria-label="Permalink to &quot;예산실적대조표&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산실적대조표</p></blockquote><p>예산 금액과 실적 금액의 증감을 계정과목별로 비교합니다.</p><h3 id="확인-포인트" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><ul><li>[ ] 예산 대비 과다 지출 항목이 있는가? → 사유 정리</li><li>[ ] 미집행 예산이 있는가? → 이월 또는 불용 처리</li><li>[ ] 추경 예산이 있다면 반영되었는가?</li></ul><hr><h2 id="_4단계-감사-준비-자료-출력-15분" tabindex="-1">4단계: 감사 준비 자료 출력 (15분) <a class="header-anchor" href="#_4단계-감사-준비-자료-출력-15분" aria-label="Permalink to &quot;4단계: 감사 준비 자료 출력 (15분)&quot;">​</a></h2><p>결산 감사를 위해 아래 자료를 출력·준비합니다.</p><table tabindex="0"><thead><tr><th>자료</th><th>메뉴 경로</th><th>화면 코드</th></tr></thead><tbody><tr><td>합계잔액시산표</td><td>결산관리 &gt; 합계잔액시산표</td><td>ACCT4010</td></tr><tr><td>대차대조표</td><td>결산관리 &gt; 대차대조표</td><td>ACCT4020</td></tr><tr><td>손익계산서</td><td>결산관리 &gt; 손익계산서</td><td>ACCT4030</td></tr><tr><td>세입세출서</td><td>결산관리 &gt; 세입세출서</td><td>ACCT4080</td></tr><tr><td>총계정원장</td><td><a href="/acct/ledger.html">장부관리</a> &gt; 총계정원장</td><td>ACCT3010</td></tr><tr><td>보조부원장</td><td><a href="/acct/ledger.html">장부관리</a> &gt; 보조부원장</td><td>ACCT3020</td></tr><tr><td>계정과목별잔액장</td><td><a href="/acct/ledger.html">장부관리</a> &gt; 계정과목별잔액장</td><td>ACCT3030</td></tr><tr><td>관리비용명세서</td><td><a href="/acct/ledger.html">장부관리</a> &gt; 관리비용명세서</td><td>ACCT3050</td></tr><tr><td>예산집행현황</td><td><a href="/acct/budget.html">예산관리</a> &gt; 예산집행현황</td><td>ACCT6020</td></tr></tbody></table><hr><h2 id="_5단계-년도이월-실행-5분" tabindex="-1">5단계: 년도이월 실행 (5분) <a class="header-anchor" href="#_5단계-년도이월-실행-5분" aria-label="Permalink to &quot;5단계: 년도이월 실행 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/settlement.html">결산관리</a> &gt; 년도이월 (ACCT4090)</p></blockquote><p>당기 잔액을 차기 연도의 기초잔액으로 이월합니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>년도이월 화면 진입</li><li>이월 대상 회계연도 확인</li><li>잔액 내역 확인</li><li><strong>이월 실행</strong></li></ol><div class="danger custom-block"><p class="custom-block-title">되돌릴 수 없습니다</p><p>년도이월은 <strong>비가역적</strong>입니다. 한 번 실행하면 취소할 수 없습니다. 반드시 아래 사항을 확인한 후 실행하세요.</p></div><h3 id="이월-전-최종-확인" tabindex="-1">이월 전 최종 확인 <a class="header-anchor" href="#이월-전-최종-확인" aria-label="Permalink to &quot;이월 전 최종 확인&quot;">​</a></h3><ul><li>[ ] 12월 월마감이 완료되었는가?</li><li>[ ] 모든 재무제표를 확인·출력했는가?</li><li>[ ] 예산 대비 실적을 확인했는가?</li><li>[ ] 감사 자료를 모두 준비했는가?</li><li>[ ] 시산표 차변 = 대변인가?</li><li>[ ] <strong>이 작업은 되돌릴 수 없다</strong>는 것을 확인했는가?</li></ul><hr><h2 id="_6단계-차기-예산-등록-15분" tabindex="-1">6단계: 차기 예산 등록 (15분) <a class="header-anchor" href="#_6단계-차기-예산-등록-15분" aria-label="Permalink to &quot;6단계: 차기 예산 등록 (15분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/budget.html">예산관리</a> &gt; 예산등록 (ACCT6010)</p></blockquote><p>새 회계연도의 예산을 입력합니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>예산등록 화면 진입</li><li>수입 예산: 계정과목별 연간 예산 금액 입력 <ul><li>항목 더블클릭 → 월별 배분 가능</li></ul></li><li>지출 예산: 계정과목별 연간 예산 금액 입력</li><li><strong>저장</strong> 클릭</li></ol><div class="tip custom-block"><p class="custom-block-title">추경예산</p><p>연중에 예산 변경이 필요하면 <strong>추경예산등록</strong>(ACCT6011)에서 수정합니다. 원본 예산은 보존됩니다.</p></div><hr><h2 id="_7단계-연말정산-급여-별도-프로세스" tabindex="-1">7단계: 연말정산 (급여) - 별도 프로세스 <a class="header-anchor" href="#_7단계-연말정산-급여-별도-프로세스" aria-label="Permalink to &quot;7단계: 연말정산 (급여) - 별도 프로세스&quot;">​</a></h2><p>직원의 연간 소득세를 정산하는 절차로, 매년 1~2월에 진행합니다.</p><p>상세 절차는 <a href="/guide/scenarios/payroll.html">급여 처리</a> 시나리오의 연말정산 부분과 <a href="/pay/year-end.html">연말정산</a> 메뉴를 참고하세요.</p><h3 id="간략-흐름" tabindex="-1">간략 흐름 <a class="header-anchor" href="#간략-흐름" aria-label="Permalink to &quot;간략 흐름&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>기본정보 등록 → 전직장 내역 → 연근로소득 등록 → 개인공제 등록</span></span>
<span class="line"><span>→ 정산 실행 → 결과 확인 → 디스켓 작성(홈택스 제출) → 환급/추징</span></span></code></pre></div><h3 id="주요-기한" tabindex="-1">주요 기한 <a class="header-anchor" href="#주요-기한" aria-label="Permalink to &quot;주요 기한&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>기한</th></tr></thead><tbody><tr><td>근로·퇴직·사업소득 지급명세서</td><td>다음 연도 <strong>3월 10일</strong></td></tr><tr><td>연말정산 디스켓 홈택스 제출</td><td><strong>2월 말</strong></td></tr></tbody></table><hr><h2 id="연말-결산-종합-체크리스트" tabindex="-1">연말 결산 종합 체크리스트 <a class="header-anchor" href="#연말-결산-종합-체크리스트" aria-label="Permalink to &quot;연말 결산 종합 체크리스트&quot;">​</a></h2><h3 id="마감-전" tabindex="-1">마감 전 <a class="header-anchor" href="#마감-전" aria-label="Permalink to &quot;마감 전&quot;">​</a></h3><ul><li>[ ] 12월 월말 마감 완료</li><li>[ ] 모든 통장 잔액 대사 완료</li><li>[ ] 미수금 잔액 확인 완료</li></ul><h3 id="재무제표" tabindex="-1">재무제표 <a class="header-anchor" href="#재무제표" aria-label="Permalink to &quot;재무제표&quot;">​</a></h3><ul><li>[ ] 시산표 차변 = 대변 확인</li><li>[ ] 대차대조표 자산 = 부채 + 자본 확인</li><li>[ ] 손익계산서 확인</li><li>[ ] 예산 대비 실적 확인</li></ul><h3 id="이월" tabindex="-1">이월 <a class="header-anchor" href="#이월" aria-label="Permalink to &quot;이월&quot;">​</a></h3><ul><li>[ ] 감사 자료 출력 완료</li><li>[ ] 년도이월 실행 완료</li><li>[ ] 차기 예산 등록 완료</li></ul><h3 id="연말정산" tabindex="-1">연말정산 <a class="header-anchor" href="#연말정산" aria-label="Permalink to &quot;연말정산&quot;">​</a></h3><ul><li>[ ] 직원 연말정산 완료</li><li>[ ] 홈택스 제출 완료</li><li>[ ] 환급/추징 급여 반영 완료</li></ul><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="년도이월-후-전년도-수정이-필요해요" tabindex="-1">년도이월 후 전년도 수정이 필요해요 <a class="header-anchor" href="#년도이월-후-전년도-수정이-필요해요" aria-label="Permalink to &quot;년도이월 후 전년도 수정이 필요해요&quot;">​</a></h3><p><strong>원인</strong>: 이월 후 전년도 오류 발견 <strong>해결</strong>: 년도이월은 되돌릴 수 없습니다. 차기 연도에서 조정 전표를 입력하여 수정하세요.</p><h3 id="차기-연도-기초잔액이-이상해요" tabindex="-1">차기 연도 기초잔액이 이상해요 <a class="header-anchor" href="#차기-연도-기초잔액이-이상해요" aria-label="Permalink to &quot;차기 연도 기초잔액이 이상해요&quot;">​</a></h3><p><strong>원인</strong>: 이월 전 재무제표 확인 미흡 <strong>해결</strong>: 기초잔액등록(ACCT1030)에서 확인하고, 필요 시 수동 조정하세요.</p><h3 id="연말정산-기한을-놓쳤어요" tabindex="-1">연말정산 기한을 놓쳤어요 <a class="header-anchor" href="#연말정산-기한을-놓쳤어요" aria-label="Permalink to &quot;연말정산 기한을 놓쳤어요&quot;">​</a></h3><p><strong>원인</strong>: 기한 미준수 <strong>해결</strong>: 지급명세서 제출 기한 초과 시 가산세가 부과됩니다. 즉시 홈택스에 제출하고, 가산세 규정을 확인하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/acct/settlement.html">결산관리</a> - 재무제표 작성</li><li><a href="/acct/budget.html">예산관리</a> - 예산 등록·집행</li><li><a href="/acct/ledger.html">장부관리</a> - 원장·보조부</li><li><a href="/acct/voucher.html">전표관리</a> - 전표 확인</li><li><a href="/pay/year-end.html">연말정산</a> - 직원 소득세 정산</li><li><a href="/guide/scenarios/month-closing.html">월말 마감</a> - 12월 마감</li></ul>`,89)])])}const b=t(i,[["render",o]]);export{p as __pageData,b as default};
